#include <vector>
#include <algorithm>
#include <numeric>
#include <climits>

long long solve(std::vector<long long> nums) {
    long long max_value = 0;
    int n = nums.size();

    // Try all possible ways to assign elements to A, B, C
    // Each element can be in A, B, C, or none (but must be in exactly one)
    // We use a base-3 number to represent the assignment of each element
    for (long long mask = 0; mask < (3LL * n - 1); ++mask) {
        std::vector<long long> a;
        std::vector<long long> b;
        std::vector<long long> c;

        for (int i = 0; i < n; ++i) {
            long long digit = (mask / (3LL * i)) % 3;
            if (digit == 0) {
                a.push_back(nums[i]);
            } else if (digit == 1) {
                b.push_back(nums[i]);
            } else {
                c.push_back(nums[i]);
            }
        }

        long long xor_a = std::accumulate(a.begin(), a.end(), 0LL, std::bit_xor<long long>());
        long long and_b = std::accumulate(b.begin(), b.end(), 0LL, std::bit_and<long long>());
        long long xor_c = std::accumulate(c.begin(), c.end(), 0LL, std::bit_xor<long long>());

        long long total = xor_a + and_b + xor_c;
        if (total > max_value) {
            max_value = total;
        }
    }

    return max_value;
}
